import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { getAuth, clearAuth } from '../utils/auth';

export default function Sidebar({ isOpen, onClose }) {
  const navigate = useNavigate();
  const auth = getAuth();
  const role = auth?.role;

  const handleLogout = () => {
    clearAuth();
    navigate('/login');
  };

  const navItems = [
    { path: '/admin/dashboard', icon: '📊', label: 'Admin Dashboard', roles: ['admin', 'manager'] },
    { path: '/leads', icon: '👥', label: 'CRM & Leads', roles: ['admin', 'manager', 'staff'] },
    { path: '/vehicles', icon: '🚗', label: 'Vehicle Inventory', roles: ['admin', 'manager', 'staff'] },
    { path: '/sales', icon: '💰', label: 'Sales Transactions', roles: ['admin', 'manager', 'staff'] },
    { path: '/appointments', icon: '📅', label: 'Appointments', roles: ['admin', 'manager', 'staff'] },
    { path: '/documents', icon: '📄', label: 'Documents', roles: ['admin', 'manager', 'staff'] },
    { path: '/admin/staff', icon: '👨‍💼', label: 'User & Role Management', roles: ['admin'] },
  ];

  const filteredItems = navItems.filter(item => item.roles.includes(role));

  const getLinkClass = ({ isActive }) => `sideItem ${isActive ? 'active' : ''}`;

  return (
    <>
      {/* Overlay for mobile */}
      {isOpen && <div className="sideOverlay" onClick={onClose}></div>}

      <aside className={`side ${isOpen ? 'open' : ''}`}>
        {/* Brand */}
        <div className="sideBrand" onClick={() => { onClose(); window.location.href = '/'; }}>
          <img src="/logo.svg" alt="Leaf Lanka" className="sideLogo" style={{ width: '56px', height: '56px', objectFit: 'contain' }} />
          <div className="sideBrandText">
            <h3>Leaf Lanka</h3>
            <p>AutoPulse System</p>
          </div>
        </div>

        {/* Navigation */}
        <nav className="sideNav">
          {filteredItems.map((item) => (
            <NavLink
              key={item.path}
              to={item.path}
              className={getLinkClass}
              onClick={onClose}
            >
              <span className="sideItemIcon">{item.icon}</span>
              <span>{item.label}</span>
            </NavLink>
          ))}
        </nav>

        {/* Footer */}
        <div className="sideFooter">
          <button
            onClick={handleLogout}
            className="sideFooterItem"
            style={{ width: '100%', border: 'none', background: 'transparent', cursor: 'pointer' }}
          >
            <span style={{ fontSize: '18px' }}>🚪</span>
            <span>Logout</span>
          </button>
        </div>
      </aside>
    </>
  );
}
